#!/usr/bin/env bash
#
# Push the latest benchmark artifacts to the bench-results branch.
#
# The bench-results branch is an orphan branch holding exactly the
# files of the most recent benchmark run, so the project README on the
# main branch can embed the plots via raw.githubusercontent URLs.
# The branch is force-pushed every run; do not commit anything to it
# by hand.
#
# Inputs:
#   $1  Commit SHA recorded in the commit message. The benchmark
#       workflow passes ${{ github.sha }}.
#
# Files expected at bench/ relative to the repo root:
#   bfhash_results.csv
#   bfhash_latency.pdf  bfhash_latency.png
#   bfhash_speedup.pdf  bfhash_speedup.png
#
# This script is intended to run inside the benchmark workflow on a
# fresh GitHub-hosted runner, where it is safe to wipe the working
# tree and check out an orphan branch. Do not run it on a developer
# laptop without understanding what git checkout --orphan does.

set -euo pipefail

if [ "$#" -ne 1 ]; then
    echo "usage: $0 <commit-sha>" >&2
    exit 1
fi

COMMIT_SHA="$1"

ARTIFACTS=(
    bench/bfhash_results.csv
    bench/bfhash_latency.pdf
    bench/bfhash_latency.png
    bench/bfhash_speedup.pdf
    bench/bfhash_speedup.png
)

# Stash artifacts outside the working tree before we wipe it.
STAGE="$(mktemp -d)"
for f in "${ARTIFACTS[@]}"; do
    if [ ! -f "$f" ]; then
        echo "expected artifact missing: $f" >&2
        exit 1
    fi
    cp "$f" "$STAGE/"
done

git config user.name  "github-actions[bot]"
git config user.email "41898282+github-actions[bot]@users.noreply.github.com"

# Switch to a brand-new orphan branch with no history. This wipes the
# working tree of any previously-checked-out files; the artifacts are
# safe in $STAGE.
git checkout --orphan bench-results
git rm -rf --quiet .

# Restore artifacts at the branch root.
cp "$STAGE"/* .

# Drop a small README so anyone who lands on this branch in the
# GitHub UI sees what it is and that it is auto-managed.
cat > README.md <<'EOF'
# bench-results

This branch is auto-generated by the benchmark workflow. It holds the
latest CI bench artifacts so the project README on the main branch can
embed the plots via raw URLs.

The branch is orphan and force-pushed on every workflow run. Do not
commit anything here by hand. Commits will be lost on the next
benchmark run.

Files:
  bfhash_results.csv     raw measurement data
  bfhash_latency.pdf     latency plot for paper figures
  bfhash_latency.png     latency plot for README embedding
  bfhash_speedup.pdf     speedup plot for paper figures
  bfhash_speedup.png     speedup plot for README embedding
EOF

git add README.md \
        bfhash_results.csv \
        bfhash_latency.pdf bfhash_latency.png \
        bfhash_speedup.pdf bfhash_speedup.png

git commit -m "Update bench results from ${COMMIT_SHA}"
git push --force origin bench-results

# Tidy up the stash (best-effort; runner is ephemeral anyway).
rm -rf "$STAGE"
